SELECT ?king ?kingLabel WHERE {
 wd:Q480 wdt:P577 ?pubDate .
 FILTER(YEAR(?pubDate) = 1605)
 ?king wdt:P39 wd:Q3847454 ;
 wdt:P580 ?start ;
 wdt:P582 ?end .
 FILTER(YEAR(?start) <= 1605 && YEAR(?end) >= 1605)
 OPTIONAL {
 ?king rdfs:label ?kingLabel .
 FILTER(LANG(?kingLabel) = 'en')
 }
}

